import React, { useState } from 'react';

const EditEmployee = ({ employee, handleUpdate, handleCancel, userRole }) => {
    const [editedEmployee, setEditedEmployee] = useState({ ...employee });

    const handleInputChange = (event) => {
        const { name, value } = event.target;
        setEditedEmployee((prevEmployee) => ({
            ...prevEmployee,
            [name]: value,
        }));
    };

    const handleSubmit = (event) => {
        event.preventDefault();
        handleUpdate(editedEmployee);
        resetForm();
    };

    const resetForm = () => {
        setEditedEmployee({
            name: '',
            surname: '',
            department: '',
            tel: '',
            mail: '',
            wage: null
            // Add other fields here
        });
    };

    return (
        <div className="container">
            <h2 className="heading">Edit Employee</h2>
            <form className="form" onSubmit={handleSubmit}>
                <div className="form-row">
                    <div className="form-group">
                        <label>
                            Employee Name:
                            <input
                                type="text"
                                name="name"
                                value={editedEmployee.name}
                                onChange={handleInputChange}
                            />
                        </label>
                    </div>
                    <div className="form-group">
                        <label>
                            Surname:
                            <input
                                type="text"
                                name="surname"
                                value={editedEmployee.surname}
                                onChange={handleInputChange}
                            />
                        </label>
                    </div>
                    <div className="form-group">
                        <label>
                            Department:
                            <input
                                type="text"
                                name="department"
                                value={editedEmployee.department}
                                onChange={handleInputChange}
                            />
                        </label>
                    </div>
                    <div className="form-group">
                        <label>
                            Tel:
                            <input
                                type="text"
                                name="tel"
                                value={editedEmployee.tel}
                                onChange={handleInputChange}
                            />
                        </label>
                    </div>
                    <div className="form-group">
                        <label>
                            Email:
                            <input
                                type="mail"
                                name="mail"
                                value={editedEmployee.mail}
                                onChange={handleInputChange}
                            />
                        </label>
                    </div>
                    <div className="form-group">
                        <label>
                            Wage:
                            <input
                                type="number"
                                name="wage"
                                value={editedEmployee.wage}
                                onChange={handleInputChange}
                            />
                        </label>
                    </div>


                    <button type="submit">Edit Employee</button>
                    <button type="button" className="add_btn" onClick={handleCancel}>
                        Cancel
                    </button>
                </div>
            </form>
        </div>
    );
};

export default EditEmployee;
